diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9df08553d86e..6e94ce5b6686 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8790,7 +8790,177 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
     }
   }

-  // Convert a sign-bit test of an FP value into a cast and integer compare.
+  // Handle fcmp (fptrunc X), C by converting to fcmp X, C' where C' is
+  // appropriately adjusted for the truncation.
+  // For example: fcmp oge (fptrunc double X), 100.0f
+  // becomes: fcmp oge double X, <threshold>
+  // where <threshold> is the midpoint between 100.0f and the previous float.
+  if (match(Op0, m_FPTrunc(m_Value(X)))) {
+    // X must be a wider FP type than the fptrunc result.
+    if (X->getType()->getScalarType()->getFPMantissaWidth() >
+        OpType->getScalarType()->getFPMantissaWidth()) {
+      const APFloat *C;
+      if (match(Op1, m_APFloat(C))) {
+        const fltSemantics &WideSem = X->getType()->getScalarType()->getFltSemantics();
+        
+        // Compute the threshold in the wider type.
+        // For >= and >, the threshold is the midpoint between C and the previous float.
+        // For <= and <, the threshold is the midpoint between C and the next float.
+        APFloat NarrowC = *C;
+        APFloat Threshold = NarrowC;
+        bool ValidThreshold = true;
+        
+        switch (Pred) {
+        case FCmpInst::FCMP_OGE:
+        case FCmpInst::FCMP_UGE: {
+          // fptrunc(x) >= C  -->  x >= midpoint(prev_float(C), C)
+          // Compute prev_float(C)
+          if (NarrowC.isInfinity() && !NarrowC.isNegative()) {
+            // C is +inf, threshold is also +inf
+            break;
+          }
+          if (NarrowC.isNaN()) {
+            ValidThreshold = false;
+            break;
+          }
+          // Get previous float value
+          APFloat PrevC = NarrowC;
+          if (PrevC.next(/*nextDown=*/true) != APFloat::opOK) {
+            ValidThreshold = false;
+            break;
+          }
+          // Compute midpoint: (PrevC + C) / 2
+          // Use wider type for the computation to avoid double rounding
+          APFloat WidePrev = PrevC;
+          APFloat WideC = NarrowC;
+          bool Lossy1, Lossy2;
+          WidePrev.convert(WideSem, APFloat::rmNearestTiesToEven, &Lossy1);
+          WideC.convert(WideSem, APFloat::rmNearestTiesToEven, &Lossy2);
+          Threshold = WidePrev;
+          Threshold.add(WideC, APFloat::rmNearestTiesToEven);
+          Threshold.divide(APFloat(2.0), APFloat::rmNearestTiesToEven);
+          break;
+        }
+        case FCmpInst::FCMP_OGT:
+        case FCmpInst::FCMP_UGT: {
+          // fptrunc(x) > C  -->  x > midpoint(C, next_float(C))
+          // This is equivalent to x >= next_value(midpoint) which we approximate
+          // as x >= midpoint(C, next_float(C)) for practical purposes
+          // Actually, for > we use the same threshold as >= but with next_float(C)
+          // fptrunc(x) > C  <==>  fptrunc(x) >= next_float(C)
+          if (NarrowC.isInfinity()) {
+            // C is +/-inf, no float value is > +inf or >= -inf
+            ValidThreshold = false;
+            break;
+          }
+          if (NarrowC.isNaN()) {
+            ValidThreshold = false;
+            break;
+          }
+          // Get next float value
+          APFloat NextC = NarrowC;
+          if (NextC.next(/*nextDown=*/false) != APFloat::opOK) {
+            ValidThreshold = false;
+            break;
+          }
+          // Now use NextC as the new C for >= comparison
+          NarrowC = NextC;
+          // Compute midpoint for NextC (same as OGE case)
+          APFloat PrevC = NarrowC;
+          if (PrevC.next(/*nextDown=*/true) != APFloat::opOK) {
+            ValidThreshold = false;
+            break;
+          }
+          APFloat WidePrev = PrevC;
+          APFloat WideC = NarrowC;
+          bool Lossy1, Lossy2;
+          WidePrev.convert(WideSem, APFloat::rmNearestTiesToEven, &Lossy1);
+          WideC.convert(WideSem, APFloat::rmNearestTiesToEven, &Lossy2);
+          Threshold = WidePrev;
+          Threshold.add(WideC, APFloat::rmNearestTiesToEven);
+          Threshold.divide(APFloat(2.0), APFloat::rmNearestTiesToEven);
+          break;
+        }
+        case FCmpInst::FCMP_OLE:
+        case FCmpInst::FCMP_ULE: {
+          // fptrunc(x) <= C  -->  x <= midpoint(C, next_float(C))
+          if (NarrowC.isInfinity() && NarrowC.isNegative()) {
+            // C is -inf, threshold is also -inf
+            break;
+          }
+          if (NarrowC.isNaN()) {
+            ValidThreshold = false;
+            break;
+          }
+          // Get next float value
+          APFloat NextC = NarrowC;
+          if (NextC.next(/*nextDown=*/false) != APFloat::opOK) {
+            ValidThreshold = false;
+            break;
+          }
+          // Compute midpoint: (C + NextC) / 2
+          APFloat WideNext = NextC;
+          APFloat WideC2 = NarrowC;
+          bool Lossy1, Lossy2;
+          WideNext.convert(WideSem, APFloat::rmNearestTiesToEven, &Lossy1);
+          WideC2.convert(WideSem, APFloat::rmNearestTiesToEven, &Lossy2);
+          Threshold = WideNext;
+          Threshold.add(WideC2, APFloat::rmNearestTiesToEven);
+          Threshold.divide(APFloat(2.0), APFloat::rmNearestTiesToEven);
+          break;
+        }
+        case FCmpInst::FCMP_OLT:
+        case FCmpInst::FCMP_ULT: {
+          // fptrunc(x) < C  -->  x < midpoint(prev_float(C), C)
+          // This is equivalent to x <= prev_value(midpoint)
+          // For < we use prev_float(C) as the new C for <= comparison
+          if (NarrowC.isInfinity()) {
+            ValidThreshold = false;
+            break;
+          }
+          if (NarrowC.isNaN()) {
+            ValidThreshold = false;
+            break;
+          }
+          // Get previous float value
+          APFloat PrevC2 = NarrowC;
+          if (PrevC2.next(/*nextDown=*/true) != APFloat::opOK) {
+            ValidThreshold = false;
+            break;
+          }
+          // Now use PrevC2 as the new C for <= comparison
+          NarrowC = PrevC2;
+          // Compute midpoint for PrevC2 (same as OLE case)
+          APFloat NextC = NarrowC;
+          if (NextC.next(/*nextDown=*/false) != APFloat::opOK) {
+            ValidThreshold = false;
+            break;
+          }
+          APFloat WideNext = NextC;
+          APFloat WideC2 = NarrowC;
+          bool Lossy1, Lossy2;
+          WideNext.convert(WideSem, APFloat::rmNearestTiesToEven, &Lossy1);
+          WideC2.convert(WideSem, APFloat::rmNearestTiesToEven, &Lossy2);
+          Threshold = WideNext;
+          Threshold.add(WideC2, APFloat::rmNearestTiesToEven);
+          Threshold.divide(APFloat(2.0), APFloat::rmNearestTiesToEven);
+          break;
+        }
+        default:
+          // For equality predicates, the optimization is more complex
+          // and may not be beneficial. Skip for now.
+          ValidThreshold = false;
+          break;
+        }
+        
+        if (ValidThreshold) {
+          Constant *NewC = ConstantFP::get(X->getType(), Threshold);
+          return new FCmpInst(Pred, X, NewC, "", &I);
+        }
+      }
+    }
+  }
+
   // TODO: Simplify if the copysign constant is 0.0 or NaN.
   // TODO: Handle non-zero compare constants.
   // TODO: Handle other predicates.

